INSERT INTO `games` (`id`, `title`, `developer`, `publisher`, `about`, `release_date`, `cover_img`, `icon`, `steam_rating`) VALUES
(34, 'Counter-Strike 2', 'Valve', 'Valve', 'For over two decades, Counter-Strike has offered an elite competitive experience, one shaped by millions of players from across the globe. And now the next chapter in the CS story is about to begin. This is Counter-Strike 2.', '2012-08-21', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/730/header.jpg?t=1749053861', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/730/capsule_231x87.jpg?t=1749053861', '4'),
(35, 'Dota 2', 'Valve', 'Valve', 'Every day, millions of players worldwide enter battle as one of over a hundred Dota heroes. And no matter if it\'s their 10th hour of play or 1,000th, there\'s always something new to discover. With regular updates that ensure a constant evolution of gameplay, features, and heroes, Dota 2 has taken on a life of its own.', '2013-07-09', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/570/header.jpg?t=1769535998', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/570/capsule_231x87.jpg?t=1769535998', '5'),
(36, 'PUBG: BATTLEGROUNDS', 'PUBG Corporation', 'KRAFTON, Inc.', 'PUBG: BATTLEGROUNDS, the high-stakes winner-take-all shooter that started the Battle Royale craze, is free-to-play! Drop into diverse maps, loot unique weapons and supplies, and survive in an ever-shrinking zone where every turn could be your last.', '2017-12-21', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/578080/841ea38bc58cabb70aef65365cf50bc2d79329d9/header.jpg?t=1778634253', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/578080/14f42ab797699a9c9f137fda66582d8776da4330/capsule_231x87.jpg?t=1778634253', '4'),
(37, 'Subnautica 2', 'Unknown Worlds Entertainment', 'Unknown Worlds Entertainment', 'Subnautica 2 is an underwater survival adventure set on an all-new alien world, developed by Unknown Worlds. Play alone or with friends in 4-player co-op. Adapt to survive by building custom bases and crafting tools. Explore the unknown to uncover the mysteries hidden within the depths.', '2026-05-14', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1962700/header.jpg?t=1778777511', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1962700/a5668b4e7176e657e2f1c70667df989ba27f64b5/capsule_231x87.jpg?t=1778777511', '4'),
(38, 'Rust', 'Facepunch Studios', 'Facepunch Studios', 'The only aim in Rust is to survive. Everything wants you to die - the island’s wildlife, other inhabitants, the environment, and other survivors. Do whatever it takes to last another night.', '2018-02-08', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/252490/header.jpg?t=1778597738', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/252490/21aac0b6e20e1ba12f635e7deb730e32a51afbd5/capsule_231x87.jpg?t=1778597738', '3'),
(39, 'Bongo Cat', 'Marcel Zurawka, Julius Krüger', 'Irox Games', 'Bongo cat needs your help. Bongo cat needz more hatz!!! Every time you press a key, Bongo cat will punch your taskbar. Type, click, play, work to collect more points. Which hats will you find?', '2025-03-05', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3419430/2e6c93c020fe13d09d8120bb9164ed7cb58f00c5/header.jpg?t=1776080084', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3419430/a72a5965134f12a6cf86879fa2eb34ba16040486/capsule_231x87.jpg?t=1776080084', '4'),
(40, 'Apex Legends™', 'Respawn', 'Electronic Arts', 'Apex Legends is the award-winning, free-to-play Hero Shooter from Respawn Entertainment. Master an ever-growing roster of legendary characters with powerful abilities, and experience strategic squad play and innovative gameplay in the next evolution of Hero Shooter and Battle Royale.', '2020-11-04', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1172470/0bd74245b869287a2dc7f682e6013f7ed08d98e3/header.jpg?t=1778502442', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1172470/b622efa206400324df2ab812786578dda4cc3537/capsule_231x87.jpg?t=1778502442', '4'),
(41, 'Slay the Spire 2', 'Mega Crit', 'Mega Crit', 'The iconic roguelike deckbuilder returns. Craft a unique deck, encounter bizarre creatures, and discover relics of immense power in Slay the Spire 2!', '2026-03-05', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2868840/b0958d387dc366211e0f353443710cfcf9fdb020/header.jpg?t=1776735385', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2868840/fb0ad136e9eaa4297a1ab3440d88ecb7209f44a2/capsule_231x87.jpg?t=1776735385', '4'),
(42, 'Grand Theft Auto V Legacy', 'Rockstar North', 'Rockstar Games', 'Grand Theft Auto V for PC offers players the option to explore the award-winning world of Los Santos and Blaine County in resolutions of up to 4k and beyond, as well as the chance to experience the game running at 60 frames per second.', '2015-04-13', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/271590/header.jpg?t=1765387725', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/271590/capsule_231x87.jpg?t=1765387725', '5'),
(43, 'Marvel Rivals', 'NetEase Games', 'NetEase Games', 'Marvel Rivals is a Super Hero Team-Based PVP Shooter! Assemble an all-star Marvel squad, devise countless strategies by combining powers to form unique Team-Up skills and fight in destructible, ever-changing battlefields across the continually evolving Marvel universe!', '2024-12-05', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2767030/dabf1f6f9513340c90c154b3cf02c9661aeaeecb/header_alt_assets_7.jpg?t=1778835753', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2767030/ea4d3060af52f3d6acfba45df822cf410ee1d029/capsule_231x87_alt_assets_7.jpg?t=1778835753', '4'),
(44, 'ARC Raiders', 'Embark Studios', 'Embark Studios', 'ARC Raiders is a multiplayer extraction adventure, set in a lethal future earth, ravaged by a mysterious mechanized threat known as ARC.', '2025-10-30', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1808500/04baafaf64a5aa5f46ecda5d71889a4848dc0628/header.jpg?t=1776865359', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1808500/542a243d39bd7ed791359be9e96c82f419b81475/capsule_231x87.jpg?t=1776865359', '4'),
(45, 'Geometry Dash', 'RobTop Games', 'RobTop Games', 'Jump and fly your way through danger in this rhythm-based action platformer!', '2014-12-22', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/322170/header.jpg?t=1775300400', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/322170/capsule_231x87.jpg?t=1775300400', '4'),
(46, 'Tom Clancy\'s Rainbow Six Siege', 'Ubisoft Montreal', 'Ubisoft', 'Rainbow Six® Siege is the reference in tactical team shooters, where elite strategy and execution triumph. Enjoy free access to Quick Match, Unranked, and Dual Front game modes with a selection of operators.', '2015-12-01', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/359550/97ce482d2a8ec5d2beb1081e954ac1ec16eea1fb/header_alt_assets_21.jpg?t=1778264604', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/359550/9ec81e90746d92acf7e539a5a4e9aa8ccc50eb7f/capsule_231x87_alt_assets_21.jpg?t=1778264604', '4'),
(47, 'Wallpaper Engine', 'Wallpaper Engine Team', 'Wallpaper Engine Team', 'Use stunning live wallpapers on your desktop. Animate your own images to create new wallpapers or import videos/websites and share them on the Steam Workshop!', '2018-11-16', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/431960/header.jpg?t=1777723277', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/431960/capsule_231x87.jpg?t=1777723277', '4'),
(48, 'Delta Force', 'Team Jade', 'TiMi Studio Group', 'Play for free in operator-based extraction and full-scale combined arms warfare. Become elite Operators, customize an ever-expanding arsenal of weapons, and deploy into thrill-packed missions across multiple modes.', '2024-12-04', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2507950/a030c943860be555324c90bed1297543c31c00ae/header_alt_assets_11.jpg?t=1776894033', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2507950/ea0d733147b05183a17d33e85bb8c518f7894fa2/capsule_231x87_alt_assets_11.jpg?t=1776894033', '4'),
(49, 'War Thunder', 'Gaijin Entertainment', 'Gaijin Network Ltd', 'War Thunder is the most comprehensive free-to-play, cross-platform, MMO military game dedicated to aviation, armoured vehicles, and naval craft, from the early 20th century to the most advanced modern combat units. Join now and take part in major battles on land, in the air, and at sea.', '2013-08-15', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/236390/ceff9434460880755b42a90b8915e87dff4482ad/header.jpg?t=1778152939', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/236390/104c3c519fdb3ba92fbe2348ebfadcebf2a7ee8f/capsule_231x87.jpg?t=1778152939', '4'),
(50, 'EA SPORTS FC™ 26', 'EA Canada, EA Romania', 'Electronic Arts', 'The Club is Yours in EA SPORTS FC™ 26. Play your way with an overhauled gameplay experience powered by community feedback, Manager Live Challenges that bring fresh storylines to the new season, and Archetypes inspired by greats of the game.', '2025-09-25', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3405690/2d96aa1b06e453cd62dae9029d412f19e61932c3/header.jpg?t=1777414590', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3405690/abca0fd9695521a046d407327d82f808162315f7/capsule_231x87.jpg?t=1777414590', '4'),
(51, 'R.E.P.O.', 'semiwork', 'semiwork', 'An online co-op horror game with up to 6 players. Locate valuable, fully physics-based objects and handle them with care as you retrieve and extract to satisfy your creator\'s desires.', '2025-02-26', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3241660/a12c92856b71315da885924ea5e1d5290c8025b8/header_alt_assets_2.jpg?t=1778158882', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3241660/e29789d09be972ea786975695bdde1cc047a76e1/capsule_231x87_alt_assets_2.jpg?t=1778158882', '4'),
(52, 'Stardew Valley', 'ConcernedApe', 'ConcernedApe', 'You\'ve inherited your grandfather\'s old farm plot in Stardew Valley. Armed with hand-me-down tools and a few coins, you set out to begin your new life. Can you learn to live off the land and turn these overgrown fields into a thriving home?', '2016-02-26', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/413150/header.jpg?t=1754692865', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/413150/capsule_231x87.jpg?t=1754692865', '4'),
(53, 'Warframe', 'Digital Extremes', 'Digital Extremes', 'Awaken as an unstoppable warrior and battle alongside your friends in this story-driven free-to-play online action game', '2013-03-25', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/230410/60ce7425b864dd3c0dd855bfc66004c6f9ca4844/header.jpg?t=1778595605', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/230410/80dd2d83df77e9037b14b0076713d2e63666192d/capsule_231x87.jpg?t=1778595605', '3'),
(54, 'Dead by Daylight', 'Behaviour Interactive Inc.', 'Behaviour Interactive Inc.', '10 years of horror. 10 years of jump scares and close calls. 10 years of brutal sacrifices and thrilling escapes. Trapped forever in a realm of eldritch evil where even death is not an escape, four determined Survivors face a bloodthirsty Killer in a vicious game of nerve and wits.', '2016-06-14', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/381210/8512297f0f02ec3e592f45b21779f61624941964/header_alt_assets_6.jpg?t=1778880603', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/381210/2c90430e51332137ca52f85da8cfc83e40755d7e/capsule_231x87_alt_assets_6.jpg?t=1778880603', '4'),
(55, 'Overwatch®', 'Blizzard Entertainment, Inc.', 'Blizzard Entertainment, Inc.', 'Overwatch®, A FUTURE WORTH FIGHTING FOR! Overwatch® is an always-on and ever-evolving free-to-play, team-based action game set in an optimistic future, where every match is the ultimate 5v5 or 6v6 battlefield brawl.', '2023-08-10', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2357570/1f84e73b8095ab9f40b1bc2c81845330979afc09/header_alt_assets_20.jpg?t=1778610036', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2357570/f40730cf4defbd8f90d0f0662d7b263dd2915fe1/capsule_231x87_alt_assets_20.jpg?t=1778610036', '4'),
(56, 'DayZ', 'Bohemia Interactive', 'Bohemia Interactive', 'How long can you survive a post-apocalyptic world? A land overrun with an infected &quot;zombie&quot; population, where you compete with other survivors for limited resources. Will you team up with strangers and stay strong together? Or play as a lone wolf to avoid betrayal? This is DayZ – this is your story.', '2018-12-13', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/221100/header.jpg?t=1769695513', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/221100/capsule_231x87.jpg?t=1769695513', '4'),
(57, 'Team Fortress 2', 'Valve', 'Valve', 'Nine distinct classes provide a broad range of tactical abilities and personalities. Constantly updated with new game modes, maps, equipment and, most importantly, hats!', '2007-10-10', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/440/header.jpg?t=1757348372', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/440/capsule_231x87.jpg?t=1757348372', '5'),
(58, 'Battlefield™ 6', 'Battlefield Studios', 'Electronic Arts', 'The ultimate all-out warfare experience. In a war of tanks, fighter jets, and massive combat arsenals, your squad is the deadliest weapon.', '2025-10-10', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2807960/c12d12ce3c7d217398d3fcad77427bfc9d57c570/header.jpg?t=1778612637', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2807960/d7ae078e0a543a97ff5a5d72165999535b0b1cdc/capsule_231x87.jpg?t=1778612637', '4'),
(59, 'Baldur\'s Gate 3', 'Larian Studios', 'Larian Studios', 'Baldur\'s Gate 3 is a story-rich, party-based RPG set in the universe of Dungeons &amp; Dragons, where your choices shape a tale of fellowship and betrayal, survival and sacrifice, and the lure of absolute power.', '2023-08-03', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1086940/48a2fcbda8565bb45025e98fd8ebde8a7203f6a0/header.jpg?t=1777363040', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1086940/3dd81008e9c385caf68152450c22353f6a8abec9/capsule_231x87.jpg?t=1777363040', '5'),
(60, 'Euro Truck Simulator 2', 'SCS Software', 'SCS Software', 'Travel across Europe as king of the road, a trucker who delivers important cargo across impressive distances! With dozens of cities to explore, your endurance, skill and speed will all be pushed to their limits.', '2012-10-12', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/227300/9a81dc3126c56637297b654f9dcac057cfd79b77/header.jpg?t=1773641450', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/227300/da84d11d3ddd817e0cca299608b469a854d75ba5/capsule_231x87.jpg?t=1773641450', '4'),
(61, 'Grand Theft Auto V Enhanced', 'Rockstar North', 'Rockstar Games', 'Experience entertainment blockbusters Grand Theft Auto V and Grand Theft Auto Online — now upgraded for a new generation with stunning visuals, faster loading, 3D audio, and more, plus exclusive content for GTA Online players.', '2025-03-04', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3240220/header.jpg?t=1765479644', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3240220/a318bd9affe8eee32984b18794b273c256e9b2d6/capsule_231x87.jpg?t=1765479644', '4'),
(62, 'Windrose', 'Kraken Express', 'Kraken Express, Pocketpair Pub', 'Embark on a PvE survival adventure in the Age of Piracy. Fight on land and sea, solo or with friends. Build, craft and explore vast open world filled with dark secrets. Master soulslite combat and take on challenging bosses, command your ship and plunder unspoken treasures!', '2026-04-14', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3041230/7e838d87d787735d5d29d72777c5ee55653dfb2b/header.jpg?t=1777529081', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3041230/6e112d27d66e13071f329e5ff68758dc18bd9a84/capsule_231x87.jpg?t=1777529081', '4'),
(63, 'Crimson Desert', 'Pearl Abyss', 'Pearl Abyss', 'Crimson Desert is an open-world action-adventure set on the continent of Pywel. Join Kliff on his journey to rebuild the Greymane faction and to save the land from a looming threat. From vast wilderness and cities to ruins and the mysterious Abyss, forge your path through battles and discovery.', '2026-03-19', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3321460/abd7dbdeaede8b6c9a6d40bf116ff2b883f2dd45/header.jpg?t=1777016399', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3321460/f4b3cbf1c0759e0f18cbc0bf13cdefa02451c95b/capsule_231x87.jpg?t=1777016399', '4'),
(64, 'Hearts of Iron IV', 'Paradox Development Studio', 'Paradox Interactive', 'Victory is at your fingertips! Your ability to lead your nation is your supreme weapon, the strategy game Hearts of Iron IV lets you take command of any nation in World War II; the most engaging conflict in world history.', '2016-06-06', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/394360/67bbd0057627fc2244793bcdd09260c2539499cf/header.jpg?t=1778590996', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/394360/08a0a8f6c28071017611aa39b835c193a27f2518/capsule_231x87.jpg?t=1778590996', '4'),
(65, 'VRChat', 'VRChat Inc.', 'VRChat Inc.', 'Join our growing community as you explore, play, and help craft the future of social VR. Create worlds and custom avatars. Welcome to VRChat.', '2017-02-01', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/438100/header.jpg?t=1762366454', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/438100/capsule_231x87.jpg?t=1762366454', '4'),
(66, 'Football Manager 26', 'Sports Interactive', 'SEGA', 'Step into the dugout and experience the future of football management.', '2025-11-04', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3551340/7d28b9aa8dcfcd96593d112736f58b4b1d3cc7a4/header.jpg?t=1775667513', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3551340/89a157ed8100b4c8fa49de9fda0b3a83aece1f5e/capsule_231x87.jpg?t=1775667513', '4'),
(67, 'Crosshair X', 'CenterPoint Gaming', 'CenterPoint Gaming', 'Improve your aim and accuracy in every game you play. Choose from thousands of community designs or create your own with the designer.', '2020-08-17', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1366800/22e1a703a4d8f45c900741b53a4f933862798a10/header.jpg?t=1778965408', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1366800/a316b8a709e0ca866266b6152d016146ae3fdc47/capsule_231x87.jpg?t=1778965408', '4'),
(68, 'Farming Simulator 25', 'GIANTS Software', 'GIANTS Software', 'Farming Simulator 25 invites you to join the rewarding farm life, single-handedly or cooperatively in multiplayer. This Farm is Your Farm!', '2024-11-12', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2300320/c2a205133d23cd24faf3c152d972a1d0177661b8/header.jpg?t=1775646645', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2300320/f56e9279a16ad2f6a0532a7ef72042d7428c00c7/capsule_231x87.jpg?t=1775646645', '4'),
(69, 'Subnautica', 'Unknown Worlds Entertainment', 'Unknown Worlds Entertainment', 'Descend into the depths of an alien underwater world filled with wonder and peril. Craft equipment, pilot submarines and out-smart wildlife to explore lush coral reefs, volcanoes, cave systems, and more - all while trying to survive.', '2018-01-23', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/264710/header.jpg?t=1777456112', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/264710/capsule_231x87.jpg?t=1777456112', '4'),
(70, 'Diablo® IV', 'Blizzard Entertainment, Inc.', 'Blizzard Entertainment, Inc.', 'Join the fight for Sanctuary in Diablo® IV, the ultimate action RPG adventure. Experience the critically acclaimed campaign and new seasonal content.', '2023-10-17', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2344520/2953f199b4c075b22c0cf8ff03d88b0b1c267823/header_alt_assets_11.jpg?t=1777501665', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2344520/498049ac91ea5e17aefa19c7e27ecdcc20e1ea67/capsule_231x87_alt_assets_11.jpg?t=1777501665', '4'),
(71, 'ELDEN RING', 'FromSoftware, Inc.', 'FromSoftware, Inc., Bandai Nam', 'THE CRITICALLY ACCLAIMED FANTASY ACTION RPG. Rise, Tarnished, and be guided by grace to brandish the power of the Elden Ring and become an Elden Lord in the Lands Between.', '2022-02-24', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1245620/header.jpg?t=1767883716', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1245620/capsule_231x87.jpg?t=1767883716', '5'),
(72, 'Call of Duty®', 'Treyarch, Raven Software, Been', 'Activision', 'The Call of Duty® experience supports Call of Duty®: Black Ops 7, Call of Duty®: Black Ops 6, and Call of Duty®: Warzone™.', '2022-10-27', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1938090/06107605348820087bb51ca89ed620c22fe559aa/header.jpg?t=1778274632', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1938090/e76dfab7877b025104a66ef5261cd30a545874c3/capsule_231x87.jpg?t=1778274632', '4'),
(73, 'Conan Exiles Enhanced', 'Funcom, Inflexion Games', 'Funcom', 'Conan Exiles Enhanced is an open world survival game set in the mythical lands of Hyboria, now fully upgraded to Unreal Engine 5 with stunning visuals and improved performance. SURVIVE, BUILD, and DOMINATE alone or with friends in a world brimming with adventure!', '2018-05-08', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/440900/b49106f92fc749db3710622258d00eb9576ecaff/header_alt_assets_7.jpg?t=1778144715', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/440900/e306c9c1b85d6cbca8f1a132f0888b7163d9b3b1/capsule_231x87_alt_assets_7.jpg?t=1778144715', '4'),
(74, 'Red Dead Redemption 2', 'Rockstar Games', 'Rockstar Games', 'Arthur Morgan and the Van der Linde Gang are outlaws on the run. With federal agents and bounty hunters massing on their heels, the gang must rob, steal, and fight their way across the rugged heartland in order to survive.', '2019-12-05', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1174180/header.jpg?t=1759502961', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1174180/capsule_231x87.jpg?t=1759502961', '5'),
(75, 'Sid Meier’s Civilization® VI', 'Firaxis Games, Aspyr (Mac), As', '2K, Aspyr (Mac), Aspyr (Linux)', 'Expand your empire, advance your culture and go head-to-head against history’s greatest leaders. Will your civilization stand the test of time?', '2016-10-20', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/289070/header.jpg?t=1740607040', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/289070/capsule_231x87.jpg?t=1740607040', '4'),
(76, 'Counter-Strike: Source', 'Valve', 'Valve', 'Counter-Strike: Source blends Counter-Strike\'s award-winning teamplay action with the advanced technology of Source™ technology.', '2004-11-01', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/240/header.jpg?t=1745368575', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/240/capsule_231x87.jpg?t=1745368575', '4'),
(77, 'The Sims™ 4', 'Maxis', 'Electronic Arts', 'Play with life and discover the possibilities. Unleash your imagination and create a world of Sims that’s wholly unique. Explore and customize every detail from Sims to homes–and much more.', '2020-06-18', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1222670/header.jpg?t=1778778231', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1222670/capsule_231x87.jpg?t=1778778231', '4'),
(78, 'Project Zomboid', 'The Indie Stone', 'The Indie Stone', 'Project Zomboid is the ultimate in zombie survival. Alone or in MP: you loot, build, craft, fight, farm and fish in a struggle to survive. A hardcore RPG skillset, a vast map, massively customisable sandbox and a cute tutorial raccoon await the unwary. So how will you die? All it takes is a bite..', '2013-11-08', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/108600/header.jpg?t=1777298596', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/108600/capsule_231x87.jpg?t=1777298596', '4'),
(79, 'Cyberpunk 2077', 'CD PROJEKT RED', 'CD PROJEKT RED', 'Cyberpunk 2077 is an open-world, action-adventure RPG set in the dark future of Night City — a dangerous megalopolis obsessed with power, glamor, and ceaseless body modification.', '2020-12-09', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1091500/e9047d8ec47ae3d94bb8b464fb0fc9e9972b4ac7/header.jpg?t=1769690377', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1091500/590e0988a2fb79f44d3e31e41fd4949eb76abc41/capsule_231x87.jpg?t=1769690377', '4'),
(80, 'PAYDAY 2', 'OVERKILL - a Starbreeze Studio', 'Starbreeze Entertainment', 'PAYDAY 2 is an action-packed, four-player co-op shooter that once again lets gamers don the masks of the original PAYDAY crew - Dallas, Hoxton, Wolf and Chains - as they descend on Washington DC for an epic crime spree.', '2013-08-13', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/218620/header.jpg?t=1778847454', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/218620/capsule_231x87.jpg?t=1778847454', '4'),
(81, 'Garry\'s Mod', 'Facepunch Studios', 'Valve', 'Garry\'s Mod is a physics sandbox. There aren\'t any predefined aims or goals. We give you the tools and leave you to play.', '2006-11-29', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/4000/header.jpg?t=1776868682', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/4000/2e52d9b905feebfdaaf2db6ad7afece10991d504/capsule_231x87.jpg?t=1776868682', '4'),
(82, 'RimWorld', 'Ludeon Studios', 'Ludeon Studios', 'A sci-fi colony sim driven by an intelligent AI storyteller. Generates stories by simulating psychology, ecology, gunplay, melee combat, climate, biomes, diplomacy, interpersonal relationships, art, medicine, trade, and more.', '2018-10-17', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/294100/76e0613b8197327299d5dbabb0a7fd7828a689a2/header.jpg?t=1776194377', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/294100/a805ac5e3ceb54a2d7d3e1c1049907f1ef8bbb89/capsule_231x87.jpg?t=1776194377', '4'),
(83, 'HELLDIVERS™ 2', 'Arrowhead Game Studios', 'PlayStation Publishing LLC', 'The Galaxy’s Last Line of Offence. Enlist in the Helldivers and join the fight for freedom across a hostile galaxy in a fast, frantic, and ferocious third-person shooter.', '2024-02-08', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/553850/f11c258b04a5e3e7771c1bab60f324ebf6c6c6fb/header.jpg?t=1770747641', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/553850/8463c7dc0ff0c0e3eef6de1688ea25f081761c99/capsule_231x87.jpg?t=1770747641', '4'),
(84, 'FINAL FANTASY XIV Online', 'Square Enix', 'Square Enix', 'Join over 30 million adventurers worldwide and take part in an epic and ever-changing FINAL FANTASY. Experience an unforgettable story, exhilarating battles, and a myriad of captivating environments to explore.', '2014-02-18', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/39210/header.jpg?t=1777372469', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/39210/2e45b2f419d0beed57ba1ff1d80a13d31f947d54/capsule_231x87.jpg?t=1777372469', '4'),
(85, 'Heroes of Might and Magic: Olden Era', 'Unfrozen', 'Hooded Horse', 'Heroes of Might and Magic: Olden Era is the official prequel hailing back to the origins of the genre-defining, critically acclaimed series of turn-based strategy games. Raise grand armies and wield devastating spells to overcome your foes in both solo and multiplayer.', '2026-04-30', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3105440/e2bef853b7cb19e3d5f019022309783609e8454f/header.jpg?t=1778780197', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3105440/740f5a03b7c20044f00041079d77b899a6a435c4/capsule_231x87.jpg?t=1778780197', '4'),
(86, 'NBA 2K26', 'Visual Concepts', '2K', 'Bragging rights are on the line in MyCAREER, MyTEAM, MyNBA, The W, and Play Now. Showcase your bag of moves with hyper realism, Powered by ProPLAY™, and challenge your friends, or rivals, in NBA 2K26’s competitive modes—and leave no doubt that you wear the crown.', '2025-09-04', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3472040/3c8f3700289081daa466b27681cd08cd2eeff04d/header_alt_assets_5.jpg?t=1778857348', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3472040/8496e0023f3b24c9bf87e1459cb9651f5a7a6732/capsule_231x87_alt_assets_5.jpg?t=1778857348', '4'),
(87, 'Total War: WARHAMMER III', 'CREATIVE ASSEMBLY, Feral Inter', 'SEGA, Feral Interactive', 'The cataclysmic conclusion to the Total War: WARHAMMER trilogy is here. Rally your forces and step into the Realm of Chaos, a dimension of mind-bending horror where the very fate of the world will be decided. Will you conquer your Daemons… or command them?', '2022-02-16', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1142710/header.jpg?t=1778863347', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1142710/capsule_231x87.jpg?t=1778863347', '4'),
(88, 'BeamNG.drive', 'BeamNG', 'BeamNG', 'A dynamic soft-body physics vehicle simulator capable of doing just about anything.', '2015-05-29', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/284160/17f8af1312bc48e6cd90e5fb639d4981682af260/header.jpg?t=1772048121', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/284160/727b938bf07eaf615baf2d9bb6ffebca1fa8b5d5/capsule_231x87.jpg?t=1772048121', '4'),
(89, 'The Elder Scrolls V: Skyrim Special Edition', 'Bethesda Game Studios', 'Bethesda Softworks', 'Winner of more than 200 Game of the Year Awards, The Elder Scrolls V: Skyrim Special Edition brings the epic fantasy to life in stunning detail. The Special Edition includes the critically acclaimed game and add-ons with all-new features.', '2016-10-27', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/489830/header.jpg?t=1753715778', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/489830/capsule_231x87.jpg?t=1753715778', '3'),
(90, 'Arena Breakout: Infinite', 'Morefun Studios', 'Morefun Studios', 'Arena Breakout: Infinite is a high-stakes tactical extraction shooter where every decision matters. Fight, loot, and extract—or lose it all. With stunningly realistic visuals, lifelike sound, and unforgiving PvPvE combat, every raid is a gamble between glory and ruin.', '2025-09-15', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2073620/cc64409cb13cecf437453e8e5d7a68615d9d97ea/header.jpg?t=1777360456', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2073620/6f34ad8408e4dc931c6d75f1e51151ac120e425a/capsule_231x87.jpg?t=1777360456', '4'),
(91, 'Counter-Strike:Global Offensive', 'Valve', 'Valve', 'Counter-Strike:Global Offensive (CS:GO) expands upon the team-based action gameplay that it pioneered when it was launched over 2 decades ago. CS:GO features new maps, characters, weapons, and game modes, and delivers updated versions of the classic CS content (de_dust2, etc.).', '2012-08-21', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/4465480/a7ec167096e887d775d775fbb8b7b5efc4186291/header.jpg?t=1774635693', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/4465480/40b14791767906c41684e775335695b26b7b3e8e/capsule_231x87.jpg?t=1774635693', '4'),
(92, 'Terraria', 'Re-Logic', 'Re-Logic', 'Dig, fight, explore, build! Nothing is impossible in this action-packed adventure game. Four Pack also available!', '2011-05-16', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/105600/header.jpg?t=1769844435', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/105600/capsule_231x87.jpg?t=1769844435', '4'),
(93, 'Mount & Blade II: Bannerlord', 'TaleWorlds Entertainment', 'TaleWorlds Entertainment', 'A strategy/action RPG. Create a character, engage in diplomacy, craft, trade and conquer new lands in a vast medieval sandbox. Raise armies to lead into battle and command and fight alongside your troops in massive real-time battles using a deep but intuitive skill-based combat system.', '2022-10-25', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/261550/header.jpg?t=1764252300', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/261550/capsule_231x87.jpg?t=1764252300', '4'),
(94, 'ARK: Survival Ascended', 'Studio Wildcard, Grove Street ', 'Studio Wildcard, Snail Games U', 'ARK is reimagined from the ground-up into the next-generation of video game technology with Unreal Engine 5! Form a tribe, tame &amp; breed hundreds of unique dinosaurs and primeval creatures, explore, craft, build, and fight your way to the top of the food-chain. Your new world awaits!', '2023-10-25', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2399830/d934813ca531af0fce69fe36bc972f1c90d1aa19/header.jpg?t=1766710980', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2399830/dce348bb9faef2c1973d04aa8a87bff18e29699b/capsule_231x87.jpg?t=1766710980', '4'),
(95, 'Rocket League®', 'Psyonix LLC', 'Psyonix LLC', 'Rocket League is a high-powered hybrid of arcade-style soccer and vehicular mayhem with easy-to-understand controls and fluid, physics-driven competition. Rocket League includes casual and competitive Online Matches, a fully-featured offline Season Mode, special “Mutators” that let you change the rules entirely, hockey and...', '2015-07-06', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/252950/1bcf75584d0c3613b02b2d0a2721a6b411375784/header_alt_assets_15.jpg?t=1773251703', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/252950/1a3343801a62bfb821b407c1c237119f26d56319/capsule_231x87_alt_assets_15.jpg?t=1773251703', '4'),
(96, 'Crusader Kings III', 'Paradox Development Studio', 'Paradox Interactive', 'Love, fight, scheme, and claim greatness. Determine your noble house’s legacy in the sprawling grand strategy of Crusader Kings III. Death is only the beginning as you guide your dynasty’s bloodline in the rich and larger-than-life simulation of the Middle Ages.', '2020-09-01', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1158310/60f31d523b52bb64ea8cadf4d6f26ef47a5f3fe9/header_alt_assets_15.jpg?t=1777568423', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1158310/2b60ce19898576e8990a52a95180b74a6f7b2631/capsule_231x87_alt_assets_15.jpg?t=1777568423', '5'),
(97, 'Black Desert', 'Pearl Abyss', 'Pearl Abyss', 'Played by over 20 million Adventurers - Black Desert Online is an open-world, action MMORPG. Experience intense, action-packed combat, battle massive world bosses, fight alongside friends to siege and conquer castles, and train in professions such as fishing, trading, crafting, cooking, and more!', '2017-05-24', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/582660/4f0ea9284b5fae9464dadc528bb572c629666313/header_alt_assets_27.jpg?t=1773974827', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/582660/8bc9b1c77608e30042d876da0cfb9f838ac535c9/capsule_231x87_alt_assets_27.jpg?t=1773974827', '4'),
(98, 'The Binding of Isaac: Rebirth', 'Nicalis, Inc., Edmund McMillen', 'Nicalis, Inc.', 'The Binding of Isaac: Rebirth is a randomly generated action RPG shooter with heavy Rogue-like elements. Following Isaac on his journey players will find bizarre treasures that change Isaac’s form giving him super human abilities and enabling him to fight off droves of mysterious creatures, discover secrets and fight his way to safety.', '2014-11-04', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/250900/header.jpg?t=1731977365', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/250900/capsule_231x87.jpg?t=1731977365', '4'),
(99, 'Valheim', 'Iron Gate AB', 'Coffee Stain Publishing', 'A brutal exploration and survival game for 1-10 players, set in a procedurally-generated purgatory inspired by viking culture. Battle, build, and conquer your way to a saga worthy of Odin’s patronage!', '2021-02-02', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/892970/de0bdcf6c008c508a79d8e75eb91fc67f4bebd5d/header.jpg?t=1765967243', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/892970/3b25991b8a19244cfd979a2766e7490cc7894e09/capsule_231x87.jpg?t=1765967243', '4'),
(100, '7 Days to Die', 'The Fun Pimps', 'The Fun Pimps Entertainment LL', '7 Days to Die is an open-world game that is a unique combination of first-person shooter, survival horror, tower defense, and role-playing games. Play the definitive zombie survival sandbox RPG that came first. Navezgane awaits!', '2024-07-25', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/251570/header.jpg?t=1776457619', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/251570/capsule_231x87.jpg?t=1776457619', '4'),
(101, 'Age of Empires II: Definitive Edition', 'World\'s Edge, Forgotten Empire', 'Xbox Game Studios', '42 Civilizations, 229 Campaign Missions, Singleplayer, Co-Op, Multiplayer, In-Game Editor, Mods, Cross-play...It is good to be the king.', '2019-11-14', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/813780/header.jpg?t=1777577197', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/813780/capsule_231x87.jpg?t=1777577197', '4'),
(102, 'Satisfactory', 'Coffee Stain Studios', 'Coffee Stain Publishing', 'Satisfactory is a first-person open-world factory building game with a dash of exploration and combat. Play alone or with friends, explore an alien planet, create multi-story factories, and enter conveyor belt heaven!', '2024-09-10', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/526870/header.jpg?t=1749717464', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/526870/fe7cbb345c177f83f829a61f0e0ab951b42c7ab1/capsule_231x87.jpg?t=1749717464', '5'),
(103, 'Left 4 Dead 2', 'Valve', 'Valve', 'Set in the zombie apocalypse, Left 4 Dead 2 is a co-operative action horror FPS takes you and your friends through the cities, swamps and cemeteries of the Deep South, from Savannah to New Orleans across five expansive campaigns.', '2009-11-16', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/550/header.jpg?t=1772742214', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/550/capsule_231x87.jpg?t=1772742214', '4'),
(104, 'Football Manager 2024', 'Sports Interactive', 'SEGA', 'Build a world-class team ready to dominate your rivals in football’s most prestigious competitions. Progress never stops when you’re pursuing footballing greatness.', '2023-11-06', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2252570/header.jpg?t=1763646323', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2252570/capsule_231x87.jpg?t=1763646323', '4'),
(105, 'Factorio', 'Wube Software LTD.', 'Wube Software LTD.', 'Factorio is a game about building and creating automated factories to produce items of increasing complexity, within an infinite 2D world. Use your imagination to design your factory, combine simple elements into ingenious structures, and finally protect it from the creatures who don\'t really like you.', '2020-08-14', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/427520/header.jpg?t=1763986204', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/427520/capsule_231x87.jpg?t=1763986204', '5'),
(106, 'ARK: Survival Evolved', 'Studio Wildcard, Instinct Game', 'Studio Wildcard, Snail Games U', 'Stranded on the shores of a mysterious island, you must learn to survive. Use your cunning to kill or tame the primeval creatures roaming the land, and encounter other players to survive, dominate... and escape!', '2017-08-27', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/346110/header.jpg?t=1765677889', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/346110/capsule_231x87.jpg?t=1765677889', '3'),
(107, 'Where Winds Meet', 'Everstone Studio', 'NetEase Games', 'Step into an open-world action-adventure RPG set in ancient China. Uncover the secrets of your own identity as you rise from a humble village wanderer to the sword master of the imperial capital. Learn martial arts and build your reputation as a hero or a bringer of chaos in this free wuxia world.', '2025-11-14', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3564740/6d94b048393d5358690a04a7db99f2c9739c703c/header.jpg?t=1777516538', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3564740/53d45054f1168cc9cfdf6bb922f141f04aea7ca4/capsule_231x87.jpg?t=1777516538', '4'),
(108, 'BidKing', 'MindSurge Network & Games', 'Elegoose Games', 'Bid King is a multiplayer tactical strategy game of bid auctions and collectible appraisal. Read your rivals, judge through uncertainty, score valuable items at low prices, and bluff others into overpaying for junk. In this auction house of deception, only one thing matters: your wits.', '2026-04-15', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/4128580/b7e0ff7f05df2c97692bc61c5d3ddf751acb3477/header.jpg?t=1776746728', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/4128580/de019d15290d2e752fee0a3aa8abe18d23806a05/capsule_231x87.jpg?t=1776746728', '4'),
(109, 'Phasmophobia', 'Kinetic Games', 'Kinetic Games', 'Phasmophobia is a 4 player online co-op psychological horror. Paranormal activity is on the rise and it’s up to you and your team to use all the ghost-hunting equipment at your disposal in order to gather as much evidence as you can.', '2020-09-18', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/739630/0a424398a10445bbb922b45771dab7118fe139d2/header_alt_assets_10.jpg?t=1778659672', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/739630/0acad9e6b3f2f9bf56bdb96cc8370542fd993b7f/capsule_231x87_alt_assets_10.jpg?t=1778659672', '4'),
(110, 'Path of Exile 2', 'Grinding Gear Games', 'Grinding Gear Games', 'Path of Exile 2 is a next generation Action RPG from Grinding Gear Games, featuring co-op for up to six players. Set years after the original Path of Exile, you will return to the dark world of Wraeclast and seek to end the corruption that is spreading.', '2024-12-06', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2694490/24eeddcbda17903f03d819588757e40845f8115f/header.jpg?t=1778193183', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2694490/bae62b5ac9eeb900458e3f6c089bf5df3eb923c9/capsule_231x87.jpg?t=1778193183', '4'),
(111, 'Don\'t Starve Together', 'Klei Entertainment', 'Klei Entertainment', 'Fight, Farm, Build and Explore Together in the standalone multiplayer expansion to the uncompromising wilderness survival game, Don\'t Starve.', '2016-04-21', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/322330/14496a5926156fbaf8b026f8224ba8c34e9b5096/header_alt_assets_49.jpg?t=1777913126', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/322330/72c1dd65c4c7b66a3bf3cba525230e94218d3d97/capsule_231x87_alt_assets_49.jpg?t=1777913126', '4'),
(112, 'STALCRAFT: X', 'EXBO', 'EXBO', 'STALCRAFT: X is the largest open-world online game in the Chernobyl Exclusion Zone. Explore the world full of mutants and anomalies alone or with friends — unforgettable emotions guaranteed.', '2022-12-09', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1818450/8a8460c659ff513e85433cbac90aea8ff9c58bdd/header.jpg?t=1778063277', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1818450/7f105573c5d1d30bcee3de955374747442d5d353/capsule_231x87.jpg?t=1778063277', '4'),
(113, 'eFootball™', 'KONAMI', 'KONAMI', 'Step up and experience the exhilarating soccer game that has now surpassed 1 billion downloads! Play eFootball™ with users around the world!', '2021-09-29', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1665460/0fb7eebc292768714f2b3be666d59b59a11b0031/header.jpg?t=1778872850', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1665460/32e6faeb8844e658d09a09f02656fd40392e05dc/capsule_231x87.jpg?t=1778872850', '4'),
(114, 'Hunt: Showdown 1896', 'Crytek', 'Crytek', 'Hunt: Showdown 1896 is the brutally rewarding extraction shooter. Track twisted monsters and overcome ruthless PvP. Take bounties in corrupted backwaters lost to history. With a team, you might survive. Die with nothing or get out with everything.', '2019-08-27', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/594650/header.jpg?t=1778853040', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/594650/db8d00180552bbcf7068dffda7bf5ce8b4ae0041/capsule_231x87.jpg?t=1778853040', '4'),
(115, 'NARAKA: BLADEPOINT', '24 Entertainment', 'NetEase Games ', 'Dive into the legends of the Far East in NARAKA: BLADEPOINT; team up with friends in fast-paced melee fights for a Battle Royale experience unlike any other. Find your playstyle with a varied cast of heroes with unique skills. More than 40 million players have already joined the fray, play free now!', '2021-08-11', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1203220/54ba28138d3123da5e078bee8714340d565cb436/header.jpg?t=1778037276', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1203220/4048c59749b8417e6532cddc2c2306e2cca485cb/capsule_231x87.jpg?t=1778037276', '4'),
(116, 'Wuthering Waves', 'KURO GAMES', 'KURO GAMES', 'Wuthering Waves is a story-rich open-world action RPG with a high degree of freedom. You wake from your slumber as Rover, joined by a vibrant cast of Resonators on a journey to reclaim your lost memories and change the world.', '2025-04-28', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3513350/86b44bb422a013c1510f029ca79ea7c4a8ffb9e8/header.jpg?t=1777505458', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3513350/57675f918025082f880eb6434e47dbdbf6cf2999/capsule_231x87.jpg?t=1777505458', '4'),
(117, 'Unturned', 'Smartly Dressed Games', 'Smartly Dressed Games', 'You\'re a survivor in the zombie infested ruins of society, and must work with your friends and forge alliances to remain among the living.', '2017-07-07', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/304930/1f4e8e4b446e210e78f3cbe60d2a696bab2a8f40/header_alt_assets_3.jpg?t=1777564986', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/304930/e198aa997fb5e11a97f5604782ea367700c976d6/capsule_231x87_alt_assets_3.jpg?t=1777564986', '4'),
(118, 'The Isle', 'Afterthought LLC', 'Afterthought LLC', 'Experience fierce open world survival gameplay as you attempt to stay alive on an unforgiving island inhabited by dinosaurs! Hunt. Grow. Survive.', '2015-12-01', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/376210/header.jpg?t=1653237914', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/376210/capsule_231x87.jpg?t=1653237914', '4'),
(119, 'Kingdom Come: Deliverance II', 'Warhorse Studios', 'Deep Silver', 'A thrilling story-driven action RPG, with a rich open world, set in 15th century Medieval Europe. Experience the ultimate medieval adventure - through the eyes of young Henry - as you embark on a journey of epic proportions.', '2025-02-04', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1771300/header.jpg?t=1777975568', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1771300/93e28946c46f09d761bbfab1e17e8c1c4a8323a0/capsule_231x87.jpg?t=1777975568', '4'),
(120, 'Sid Meier\'s Civilization® V', 'Firaxis Games, Aspyr (Mac), As', '2K, Aspyr (Mac), Aspyr (Linux)', 'Create, discover, and download new player-created maps, scenarios, interfaces, and more!', '2010-09-23', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/8930/header.jpg?t=1724341158', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/8930/capsule_231x87.jpg?t=1724341158', '5'),
(121, 'Stellaris', 'Paradox Development Studio', 'Paradox Interactive', 'Explore a galaxy full of wonders in this sci-fi grand strategy game from Paradox Development Studios. Interact with diverse alien races, discover strange new worlds with unexpected events and expand the reach of your empire. Each new adventure holds almost limitless possibilities.', '2016-05-09', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/281990/3e1fd59709cf82b6ad682760bcd2622068d05bd8/header_alt_assets_11.jpg?t=1779090735', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/281990/a41fbf837417238359b4972ec96de4d241424292/capsule_231x87_alt_assets_11.jpg?t=1779090735', '4');
INSERT INTO `games` (`id`, `title`, `developer`, `publisher`, `about`, `release_date`, `cover_img`, `icon`, `steam_rating`) VALUES
(122, 'Enshrouded', 'Keen Games GmbH', 'Keen Games GmbH', 'You are Flameborn, last ember of hope of a dying race. Awaken, survive the terror of a corrupting fog, and reclaim the lost beauty of your kingdom. Venture into a vast world, vanquish punishing bosses, build grand halls and forge your path in this co-op survival action RPG for up to 16 players.', '2024-01-24', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1203620/062c788d22ecf236269da0f115150c0d3b7055a4/header.jpg?t=1776758849', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1203620/84d7ce762d0e0ad6a2dfdced85ea713d33b70e18/capsule_231x87.jpg?t=1776758849', '4'),
(123, 'Arma Reforger', 'Bohemia Interactive', 'Bohemia Interactive', 'Engage in massive combined arms battles, create and curate combat missions in real time, and shape your experience with endless community mods. Deploy into the Cold War and experience the most authentic and immersive military sandbox ever created.', '2023-11-16', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1874880/header.jpg?t=1773999249', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1874880/capsule_231x87.jpg?t=1773999249', '4'),
(124, 'Schedule I', 'TVGS', 'TVGS', 'From small-time dope pusher to kingpin - manufacture and distribute a range of drugs throughout the grungy city of Hyland Point. Expand your empire with properties, businesses, employees and more.', '2025-03-24', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3164500/header.jpg?t=1773974661', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3164500/986ee9a7a25cb0e61d1530cc3cd7e3e06aa68733/capsule_231x87.jpg?t=1773974661', '4'),
(125, 'ELDEN RING NIGHTREIGN', 'FromSoftware, Inc.', 'FromSoftware, Inc., Bandai Nam', 'ELDEN RING NIGHTREIGN is a standalone adventure within the ELDEN RING universe, crafted to offer players a new gaming experience by reimagining the game’s core design.', '2025-05-29', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2622380/header.jpg?t=1773099036', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2622380/8ebc4260af27bc55ba8b88982fd7eb7f970d43c9/capsule_231x87.jpg?t=1773099036', '4'),
(126, 'Palworld', 'Pocketpair', 'Pocketpair', 'Fight, farm, build and work alongside mysterious creatures called &quot;Pals&quot; in this completely new multiplayer, open world survival and crafting game!', '2024-01-18', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1623730/058bd87dc17a7179e07c446aa64d0574ca43ab9d/header.jpg?t=1773936597', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1623730/4f823e476ad290ad4f19763e7d800723df422dfa/capsule_231x87.jpg?t=1773936597', '4'),
(127, 'THE FINALS', 'Embark Studios', 'Embark Studios', 'THE FINALS is the world’s first Dynamism Shooter, a free-to-play, fast-paced, physics-driven, first-person shooter set on the stage of the biggest Gameshow of the future! Fight for Fans and fortune in fully-destructible, virtual Arenas that guarantee no two rounds will ever play the same!', '2023-12-07', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2073850/699da40c69cc8b1b3f86c89a6a925b04535672da/header.jpg?t=1778695694', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2073850/dc50f757c463cc1f7cadbd61a4e63e3ba8d566fa/capsule_231x87.jpg?t=1778695694', '4'),
(128, 'Counter-Strike 2', 'Valve', 'Valve', 'For over two decades, Counter-Strike has offered an elite competitive experience, one shaped by millions of players from across the globe. And now the next chapter in the CS story is about to begin. This is Counter-Strike 2.', '2012-08-21', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/730/header.jpg?t=1749053861', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/730/capsule_231x87.jpg?t=1749053861', '4'),
(129, 'Dota 2', 'Valve', 'Valve', 'Every day, millions of players worldwide enter battle as one of over a hundred Dota heroes. And no matter if it\'s their 10th hour of play or 1,000th, there\'s always something new to discover. With regular updates that ensure a constant evolution of gameplay, features, and heroes, Dota 2 has taken on a life of its own.', '2013-07-09', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/570/header.jpg?t=1769535998', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/570/capsule_231x87.jpg?t=1769535998', '5'),
(130, 'PUBG: BATTLEGROUNDS', 'PUBG Corporation', 'KRAFTON, Inc.', 'PUBG: BATTLEGROUNDS, the high-stakes winner-take-all shooter that started the Battle Royale craze, is free-to-play! Drop into diverse maps, loot unique weapons and supplies, and survive in an ever-shrinking zone where every turn could be your last.', '2017-12-21', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/578080/841ea38bc58cabb70aef65365cf50bc2d79329d9/header.jpg?t=1778634253', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/578080/14f42ab797699a9c9f137fda66582d8776da4330/capsule_231x87.jpg?t=1778634253', '4'),
(131, 'Subnautica 2', 'Unknown Worlds Entertainment', 'Unknown Worlds Entertainment', 'Subnautica 2 is an underwater survival adventure set on an all-new alien world, developed by Unknown Worlds. Play alone or with friends in 4-player co-op. Adapt to survive by building custom bases and crafting tools. Explore the unknown to uncover the mysteries hidden within the depths.', '2026-05-14', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1962700/header.jpg?t=1778777511', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1962700/a5668b4e7176e657e2f1c70667df989ba27f64b5/capsule_231x87.jpg?t=1778777511', '4'),
(132, 'Rust', 'Facepunch Studios', 'Facepunch Studios', 'The only aim in Rust is to survive. Everything wants you to die - the island’s wildlife, other inhabitants, the environment, and other survivors. Do whatever it takes to last another night.', '2018-02-08', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/252490/header.jpg?t=1778597738', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/252490/21aac0b6e20e1ba12f635e7deb730e32a51afbd5/capsule_231x87.jpg?t=1778597738', '3'),
(133, 'Bongo Cat', 'Marcel Zurawka, Julius Krüger', 'Irox Games', 'Bongo cat needs your help. Bongo cat needz more hatz!!! Every time you press a key, Bongo cat will punch your taskbar. Type, click, play, work to collect more points. Which hats will you find?', '2025-03-05', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3419430/2e6c93c020fe13d09d8120bb9164ed7cb58f00c5/header.jpg?t=1776080084', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3419430/a72a5965134f12a6cf86879fa2eb34ba16040486/capsule_231x87.jpg?t=1776080084', '4'),
(134, 'Apex Legends™', 'Respawn', 'Electronic Arts', 'Apex Legends is the award-winning, free-to-play Hero Shooter from Respawn Entertainment. Master an ever-growing roster of legendary characters with powerful abilities, and experience strategic squad play and innovative gameplay in the next evolution of Hero Shooter and Battle Royale.', '2020-11-04', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1172470/0bd74245b869287a2dc7f682e6013f7ed08d98e3/header.jpg?t=1778502442', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1172470/b622efa206400324df2ab812786578dda4cc3537/capsule_231x87.jpg?t=1778502442', '4'),
(135, 'Slay the Spire 2', 'Mega Crit', 'Mega Crit', 'The iconic roguelike deckbuilder returns. Craft a unique deck, encounter bizarre creatures, and discover relics of immense power in Slay the Spire 2!', '2026-03-05', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2868840/b0958d387dc366211e0f353443710cfcf9fdb020/header.jpg?t=1776735385', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2868840/fb0ad136e9eaa4297a1ab3440d88ecb7209f44a2/capsule_231x87.jpg?t=1776735385', '4'),
(136, 'Grand Theft Auto V Legacy', 'Rockstar North', 'Rockstar Games', 'Grand Theft Auto V for PC offers players the option to explore the award-winning world of Los Santos and Blaine County in resolutions of up to 4k and beyond, as well as the chance to experience the game running at 60 frames per second.', '2015-04-13', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/271590/header.jpg?t=1765387725', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/271590/capsule_231x87.jpg?t=1765387725', '5'),
(137, 'Marvel Rivals', 'NetEase Games', 'NetEase Games', 'Marvel Rivals is a Super Hero Team-Based PVP Shooter! Assemble an all-star Marvel squad, devise countless strategies by combining powers to form unique Team-Up skills and fight in destructible, ever-changing battlefields across the continually evolving Marvel universe!', '2024-12-05', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2767030/dabf1f6f9513340c90c154b3cf02c9661aeaeecb/header_alt_assets_7.jpg?t=1778835753', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2767030/ea4d3060af52f3d6acfba45df822cf410ee1d029/capsule_231x87_alt_assets_7.jpg?t=1778835753', '4'),
(138, 'ARC Raiders', 'Embark Studios', 'Embark Studios', 'ARC Raiders is a multiplayer extraction adventure, set in a lethal future earth, ravaged by a mysterious mechanized threat known as ARC.', '2025-10-30', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1808500/04baafaf64a5aa5f46ecda5d71889a4848dc0628/header.jpg?t=1776865359', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/1808500/542a243d39bd7ed791359be9e96c82f419b81475/capsule_231x87.jpg?t=1776865359', '4'),
(139, 'Geometry Dash', 'RobTop Games', 'RobTop Games', 'Jump and fly your way through danger in this rhythm-based action platformer!', '2014-12-22', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/322170/header.jpg?t=1775300400', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/322170/capsule_231x87.jpg?t=1775300400', '4'),
(140, 'Tom Clancy\'s Rainbow Six Siege', 'Ubisoft Montreal', 'Ubisoft', 'Rainbow Six® Siege is the reference in tactical team shooters, where elite strategy and execution triumph. Enjoy free access to Quick Match, Unranked, and Dual Front game modes with a selection of operators.', '2015-12-01', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/359550/97ce482d2a8ec5d2beb1081e954ac1ec16eea1fb/header_alt_assets_21.jpg?t=1778264604', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/359550/9ec81e90746d92acf7e539a5a4e9aa8ccc50eb7f/capsule_231x87_alt_assets_21.jpg?t=1778264604', '4'),
(141, 'Wallpaper Engine', 'Wallpaper Engine Team', 'Wallpaper Engine Team', 'Use stunning live wallpapers on your desktop. Animate your own images to create new wallpapers or import videos/websites and share them on the Steam Workshop!', '2018-11-16', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/431960/header.jpg?t=1777723277', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/431960/capsule_231x87.jpg?t=1777723277', '4'),
(142, 'Delta Force', 'Team Jade', 'TiMi Studio Group', 'Play for free in operator-based extraction and full-scale combined arms warfare. Become elite Operators, customize an ever-expanding arsenal of weapons, and deploy into thrill-packed missions across multiple modes.', '2024-12-04', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2507950/a030c943860be555324c90bed1297543c31c00ae/header_alt_assets_11.jpg?t=1776894033', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/2507950/ea0d733147b05183a17d33e85bb8c518f7894fa2/capsule_231x87_alt_assets_11.jpg?t=1776894033', '4'),
(143, 'War Thunder', 'Gaijin Entertainment', 'Gaijin Network Ltd', 'War Thunder is the most comprehensive free-to-play, cross-platform, MMO military game dedicated to aviation, armoured vehicles, and naval craft, from the early 20th century to the most advanced modern combat units. Join now and take part in major battles on land, in the air, and at sea.', '2013-08-15', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/236390/ceff9434460880755b42a90b8915e87dff4482ad/header.jpg?t=1778152939', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/236390/104c3c519fdb3ba92fbe2348ebfadcebf2a7ee8f/capsule_231x87.jpg?t=1778152939', '4'),
(144, 'EA SPORTS FC™ 26', 'EA Canada, EA Romania', 'Electronic Arts', 'The Club is Yours in EA SPORTS FC™ 26. Play your way with an overhauled gameplay experience powered by community feedback, Manager Live Challenges that bring fresh storylines to the new season, and Archetypes inspired by greats of the game.', '2025-09-25', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3405690/2d96aa1b06e453cd62dae9029d412f19e61932c3/header.jpg?t=1777414590', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3405690/abca0fd9695521a046d407327d82f808162315f7/capsule_231x87.jpg?t=1777414590', '4'),
(145, 'R.E.P.O.', 'semiwork', 'semiwork', 'An online co-op horror game with up to 6 players. Locate valuable, fully physics-based objects and handle them with care as you retrieve and extract to satisfy your creator\'s desires.', '2025-02-26', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3241660/a12c92856b71315da885924ea5e1d5290c8025b8/header_alt_assets_2.jpg?t=1778158882', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/3241660/e29789d09be972ea786975695bdde1cc047a76e1/capsule_231x87_alt_assets_2.jpg?t=1778158882', '4'),
(146, 'Stardew Valley', 'ConcernedApe', 'ConcernedApe', 'You\'ve inherited your grandfather\'s old farm plot in Stardew Valley. Armed with hand-me-down tools and a few coins, you set out to begin your new life. Can you learn to live off the land and turn these overgrown fields into a thriving home?', '2016-02-26', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/413150/header.jpg?t=1754692865', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/413150/capsule_231x87.jpg?t=1754692865', '4'),
(147, 'Warframe', 'Digital Extremes', 'Digital Extremes', 'Awaken as an unstoppable warrior and battle alongside your friends in this story-driven free-to-play online action game', '2013-03-25', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/230410/60ce7425b864dd3c0dd855bfc66004c6f9ca4844/header.jpg?t=1778595605', 'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/230410/80dd2d83df77e9037b14b0076713d2e63666192d/capsule_231x87.jpg?t=1778595605', '3');
INSERT INTO `media` (`id`, `game_id`, `source`) VALUES
